import json
from datetime import datetime, date

def transform_users(json_str):
    """Transform a JSON array of user objects.
    Each user has 'first_name', 'last_name', 'email', 'age'.
    Return a list of dicts with 'full_name' (first + last),
    'email', and 'is_adult' (age >= 18)."""
    users = json.loads(json_str)
    result = []
    for user in users:
        result.append({
            'full_name': f"{user['first_name']} {user['last_name']}",
            'email': user['email'],
            'is_adult': user['age'] >= 18
        })
    return result

def group_by_key(json_str, key):
    """Parse a JSON array of objects and group them by the specified key.
    Return a dict mapping key values to lists of objects."""
    items = json.loads(json_str)
    groups = {}
    for item in items:
        group_val = item[key]
        if group_val not in groups:
            groups[group_val] = []
        groups[group_val].append(item)
    return groups

def json_diff(json1, json2):
    """Compare two JSON strings and return a dict with:
    'added' (keys in json2 not in json1),
    'removed' (keys in json1 not in json2),
    'changed' (keys present in both but with different values)."""
    obj1 = json.loads(json1)
    obj2 = json.loads(json2)
    keys1 = set(obj1.keys())
    keys2 = set(obj2.keys())
    added = sorted(keys2 - keys1)
    removed = sorted(keys1 - keys2)
    changed = sorted(k for k in keys1 & keys2 if obj1[k] != obj2[k])
    return {
        'added': added,
        'removed': removed,
        'changed': changed
    }

def serialize_custom(obj):
    """Serialize a Python object to a JSON string.
    Handle datetime objects (as ISO format strings),
    sets (as sorted lists), and custom objects (as their __dict__)."""
    def default_handler(o):
        if isinstance(o, (datetime, date)):
            return o.isoformat()
        elif isinstance(o, set):
            return sorted(o)
        elif hasattr(o, '__dict__'):
            return o.__dict__
        raise TypeError(f'Object of type {type(o).__name__} is not JSON serializable')
    return json.dumps(obj, default=default_handler, sort_keys=True)
